import numpy as np
import tensorflow as tf

class DropoutLayer:
    def __init__(self, p: float):
        if not 0 <= p < 1:
            raise ValueError("Dropout rate p must be in [0, 1)")
        self.p = p
        self.mask = None

    def forward(self, x: np.ndarray, training: bool = True) -> np.ndarray:
        x_tensor = tf.constant(x, dtype=tf.float32)
        if not training or self.p == 0:
            return x_tensor.numpy()
        keep_prob = 1.0 - self.p
        # Use TF to generate the mask
        random_mask = tf.cast(
            tf.random.uniform(shape=tf.shape(x_tensor)) >= self.p,
            dtype=tf.float32
        ) / keep_prob
        self.mask = random_mask.numpy()
        return (x_tensor * random_mask).numpy()

    def backward(self, grad: np.ndarray) -> np.ndarray:
        if self.mask is None:
            return grad
        grad_tensor = tf.constant(grad, dtype=tf.float32)
        mask_tensor = tf.constant(self.mask, dtype=tf.float32)
        return (grad_tensor * mask_tensor).numpy()


# --- GradientTape version (idiomatic TF) ---
class DropoutLayerTF(tf.keras.layers.Layer):
    def __init__(self, p: float, **kwargs):
        super().__init__(**kwargs)
        if not 0 <= p < 1:
            raise ValueError("Dropout rate p must be in [0, 1)")
        self.p = p
        self._mask = None

    def call(self, x, training=None):
        if not training or self.p == 0:
            return x
        keep_prob = 1.0 - self.p
        mask = tf.cast(
            tf.random.uniform(tf.shape(x)) >= self.p,
            dtype=x.dtype
        ) / keep_prob
        self._mask = mask
        return x * mask

    def get_mask(self):
        return self._mask


# Demo with GradientTape
if __name__ == '__main__':
    layer = DropoutLayerTF(p=0.3)
    x = tf.Variable(np.random.randn(3, 4).astype(np.float32))
    with tf.GradientTape() as tape:
        out = layer(x, training=True)
        loss = tf.reduce_sum(out)
    grad = tape.gradient(loss, x)
    print('Input:\n', x.numpy())
    print('Output:\n', out.numpy())
    print('Gradient (should match mask * 1.0):\n', grad.numpy())
    print('Stored mask:\n', layer.get_mask().numpy())

