import numpy as np
import torch
import torch.nn as nn

class DropoutLayer:
    """Manual implementation matching the problem's numpy interface."""
    def __init__(self, p: float):
        if not 0 <= p < 1:
            raise ValueError("Dropout rate p must be in [0, 1)")
        self.p = p
        self.mask = None

    def forward(self, x: np.ndarray, training: bool = True) -> np.ndarray:
        if not training or self.p == 0:
            return x
        keep_prob = 1.0 - self.p
        x_t = torch.tensor(x, dtype=torch.float32)
        mask_t = (torch.rand_like(x_t) >= self.p).float() / keep_prob
        self.mask = mask_t.numpy()
        return (x_t * mask_t).numpy()

    def backward(self, grad: np.ndarray) -> np.ndarray:
        if self.mask is None:
            return grad
        return grad * self.mask


# --- Idiomatic PyTorch with autograd ---
class DropoutFunction(torch.autograd.Function):
    @staticmethod
    def forward(ctx, x, p, training):
        if not training or p == 0:
            return x
        keep_prob = 1.0 - p
        mask = (torch.rand_like(x) >= p).float() / keep_prob
        ctx.save_for_backward(mask)
        return x * mask

    @staticmethod
    def backward(ctx, grad_output):
        mask, = ctx.saved_tensors
        return grad_output * mask, None, None  # None for p and training grads


class DropoutLayerTorch(nn.Module):
    def __init__(self, p: float):
        super().__init__()
        if not 0 <= p < 1:
            raise ValueError("Dropout rate p must be in [0, 1)")
        self.p = p

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return DropoutFunction.apply(x, self.p, self.training)


# Demo
if __name__ == '__main__':
    model = DropoutLayerTorch(p=0.4)

    # Training mode
    model.train()
    x = torch.ones(3, 5, requires_grad=True)
    out = model(x)
    loss = out.sum()
    loss.backward()
    print('Training output:\n', out.detach().numpy())
    print('Gradient on x:\n', x.grad.numpy())

    # Eval mode
    model.eval()
    with torch.no_grad():
        out_eval = model(x)
    print('Eval output (should equal input):\n', out_eval.numpy())
